// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_M 100005
#define INF 1000000000

// Define the structure for a ticket
typedef struct {
    int v, k, w;
} Ticket;

// Define the structure for a graph
typedef struct {
    int n, m;
    int **adj;
    Ticket *tickets;
} Graph;

// Function to create a graph
Graph *createGraph(int n, int m) {
    Graph *g = (Graph *)malloc(sizeof(Graph));
    g->n = n;
    g->m = m;
    g->adj = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        g->adj[i] = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            g->adj[i][j] = INF;
        }
    }
    g->tickets = (Ticket *)malloc(m * sizeof(Ticket));
    return g;
}

// Function to add an edge to the graph
void addEdge(Graph *g, int a, int b) {
    g->adj[a][b] = 1;
}

// Function to add a ticket to the graph
void addTicket(Graph *g, int v, int k, int w) {
    Ticket t;
    t.v = v;
    t.k = k;
    t.w = w;
    g->tickets[g->m++] = t;
}

// Function to calculate the minimum cost
int minCost(Graph *g, int city) {
    // Base case: if the city is the capital, return 0
    if (city == 0) return 0;

    // Initialize the minimum cost to infinity
    int min = INF;

    // Iterate over all tickets that can be bought in the current city
    for (int i = 0; i < g->m; i++) {
        Ticket t = g->tickets[i];
        if (t.v == city) {
            // Calculate the cost of using the current ticket
            int cost = t.w;
            // Calculate the minimum cost to reach the capital using the current ticket
            int minCostUsingTicket = minCost(g, city - 1) + cost;
            // Update the minimum cost if using the current ticket is cheaper
            if (minCostUsingTicket < min) {
                min = minCostUsingTicket;
            }
        }
    }

    // Return the minimum cost
    return min;
}

int main() {
    int n, m, q;
    scanf("%d %d", &n, &m);
    Graph *g = createGraph(n, m);
    for (int i = 0; i < n - 1; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        addEdge(g, a, b);
    }
    for (int i = 0; i < m; i++) {
        int v, k, w;
        scanf("%d %d %d", &v, &k, &w);
        addTicket(g, v, k, w);
    }
    scanf("%d", &q);
    for (int i = 0; i < q; i++) {
        int city;
        scanf("%d", &city);
        printf("%d\n", minCost(g, city));
    }
    return 0;
}

