    }
    for (int i = 0; i < m; i++) {
        int v, k, w;
        cin >> v >> k >> w;
        addTicket(g, v, k, w);
    }
    cin >> q;
    for (int i = 0; i < q; i++) {
        int city;
        cin >> city;
        cout << minCost(g, city) << endl;
    }
    return 0;
}

