import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    // Define the structure for a ticket
    static class Ticket {
        int v, k, w;
        Ticket(int v, int k, int w) {
            this.v = v;
            this.k = k;
            this.w = w;
        }
    }

    // Define the structure for a graph
    static class Graph {
        int n, m;
        int[][] adj;
        ArrayList<Ticket> tickets;
        Graph(int n, int m) {
            this.n = n;
            this.m = m;
            adj = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    adj[i][j] = Integer.MAX_VALUE;
                }
            }
            tickets = new ArrayList<>();
        }
    }

    // Function to add an edge to the graph
    static void addEdge(Graph g, int a, int b) {
        g.adj[a][b] = 1;
    }

    // Function to add a ticket to the graph
    static void addTicket(Graph g, int v, int k, int w) {
        Ticket t = new Ticket(v, k, w);
        g.tickets.add(t);
    }

    // Function to calculate the minimum cost
    static int minCost(Graph g, int city) {
        // Base case: if the city is the capital, return 0
        if (city == 0) return 0;

        // Initialize the minimum cost to infinity
        int min = Integer.MAX_VALUE;

        // Iterate over all tickets that can be bought in the current city
        for (Ticket t : g.tickets) {
            if (t.v == city) {
                // Calculate the cost of using the current ticket
                int cost = t.w;
                // Calculate the minimum cost to reach the capital using the current ticket
                int minCostUsingTicket = minCost(g, city - 1) + cost;
                // Update the minimum cost if using the current ticket is cheaper
                if (minCostUsingTicket < min) {
                    min = minCostUsingTicket;
                }
            }
        }

        // Return the minimum cost
        return min;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        Graph g = new Graph(n, m);
        for (int i = 0; i < n - 1; i++) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            addEdge(g, a, b);
        }
        for (int i = 0; i < m; i++) {
            int v = sc.nextInt();
            int k = sc.nextInt();
            int w = sc.nextInt();
            addTicket(g, v, k, w);
        }
        int q = sc.nextInt();
        for (int i = 0; i < q; i++) {
            int city = sc.nextInt();
            System.out.println(minCost(g, city));
        }
    }
}

